create or replace function public.enforce_workflow_scope() returns trigger language plpgsql security definer set search_path=public as $$ begin if tg_table_name='workflow_versions' and not exists(select 1 from public.workflow_definitions d where d.id=new.definition_id and d.tenant_id=new.tenant_id and d.organization_id=new.organization_id and d.facility_id is not distinct from new.facility_id) then raise exception 'Workflow version scope mismatch' using errcode='23503'; end if; if tg_table_name='workflow_instances' and not exists(select 1 from public.workflow_versions v where v.id=new.workflow_version_id and v.status='published' and v.tenant_id=new.tenant_id and v.organization_id=new.organization_id and v.facility_id is not distinct from new.facility_id) then raise exception 'Workflow instance requires published version in scope' using errcode='23503'; end if; if tg_table_name in ('workflow_events','workflow_tasks','workflow_approvals','workflow_comments','workflow_reminders') and not exists(select 1 from public.workflow_instances i where i.id=new.instance_id and i.tenant_id=new.tenant_id and i.organization_id=new.organization_id and i.facility_id is not distinct from new.facility_id) then raise exception 'Workflow child scope mismatch' using errcode='23503'; end if; return new; end $$;
create trigger workflow_versions_scope before insert or update on public.workflow_versions for each row execute function public.enforce_workflow_scope(); create trigger workflow_instances_scope before insert or update on public.workflow_instances for each row execute function public.enforce_workflow_scope(); create trigger workflow_events_scope before insert or update on public.workflow_events for each row execute function public.enforce_workflow_scope(); create trigger workflow_tasks_scope before insert or update on public.workflow_tasks for each row execute function public.enforce_workflow_scope(); create trigger workflow_approvals_scope before insert or update on public.workflow_approvals for each row execute function public.enforce_workflow_scope(); create trigger workflow_comments_scope before insert or update on public.workflow_comments for each row execute function public.enforce_workflow_scope(); create trigger workflow_reminders_scope before insert or update on public.workflow_reminders for each row execute function public.enforce_workflow_scope();
create or replace function public.validate_workflow_definition(p_definition jsonb) returns boolean language plpgsql security definer set search_path=public as $$ declare initial_count int; begin if p_definition ? 'states' is false or p_definition ? 'transitions' is false then return false; end if; select count(*) into initial_count from jsonb_array_elements(p_definition->'states') s where coalesce((s->>'initial')::boolean,false); if initial_count<>1 then return false; end if; if exists(select 1 from jsonb_array_elements(p_definition->'states') s group by s->>'key' having count(*)>1) or exists(select 1 from jsonb_array_elements(p_definition->'transitions') t group by t->>'key' having count(*)>1) then return false; end if; if p_definition::text ~* '(javascript|<script|select |insert |update |delete |drop |;)' then return false; end if; if exists(select 1 from jsonb_array_elements(p_definition->'transitions') t, jsonb_array_elements(coalesce(t->'conditions','[]'::jsonb)) c where c->>'operator' not in ('equals','not_equals','contains','greater_than','less_than','date_overdue','has_role','has_permission','department','facility','severity_threshold','risk_threshold','ncc_merp_threshold','finding_critical','approval_status','task_status')) then return false; end if; if exists(select 1 from jsonb_array_elements(p_definition->'transitions') t, jsonb_array_elements(coalesce(t->'actions','[]'::jsonb)) a where a->>'kind' not in ('assign_user','assign_role','assign_department','create_task','request_approval','set_due_date','timeline','audit','notification','reminder','escalate','lock','unlock','capa_request','update_allowlisted_field','follow_up')) then return false; end if; return true; end $$;
create or replace function public.publish_workflow_version(p_definition_id uuid,p_version_id uuid) returns void language plpgsql security definer set search_path=public as $$ declare v public.workflow_versions%rowtype; begin select * into v from public.workflow_versions where id=p_version_id for update; if not found or v.definition_id<>p_definition_id or v.status<>'approved' or not public.can_workflow('workflows.publish',v.tenant_id,v.organization_id,v.facility_id) or not public.validate_workflow_definition(v.definition) then raise exception 'Workflow publication denied'; end if; update public.workflow_versions set status='published',updated_at=now(),updated_by=auth.uid() where id=v.id; update public.workflow_definitions set status='published',current_version_id=v.id,updated_at=now(),updated_by=auth.uid() where id=p_definition_id; end $$;
create or replace function public.record_trusted_workflow_event(p_instance_id uuid,p_kind text,p_action text,p_metadata jsonb default '{}'::jsonb) returns void language plpgsql security definer set search_path=public as $$ declare i public.workflow_instances%rowtype; begin select * into i from public.workflow_instances where id=p_instance_id for update; if not found or not public.can_workflow('workflows.transition',i.tenant_id,i.organization_id,i.facility_id) then raise exception 'Workflow event denied'; end if; insert into public.workflow_events(instance_id,tenant_id,organization_id,facility_id,kind,action,metadata,created_by) values(i.id,i.tenant_id,i.organization_id,i.facility_id,p_kind,p_action,p_metadata,auth.uid()); end $$;
create or replace function public.start_workflow_instance(p_version_id uuid,p_source_type text,p_source_id uuid,p_state text) returns uuid language plpgsql security definer set search_path=public as $$ declare v public.workflow_versions%rowtype; new_id uuid; begin select * into v from public.workflow_versions where id=p_version_id for update; if not found or v.status<>'published' or not public.can_workflow('workflows.start',v.tenant_id,v.organization_id,v.facility_id) then raise exception 'Workflow start denied'; end if; insert into public.workflow_instances(workflow_version_id,tenant_id,organization_id,facility_id,source_type,source_id,state_key,created_by,updated_by) values(v.id,v.tenant_id,v.organization_id,v.facility_id,p_source_type,p_source_id,p_state,auth.uid(),auth.uid()) returning id into new_id; perform public.record_trusted_workflow_event(new_id,'system','instance.started'); return new_id; end $$;
create or replace function public.transition_workflow_instance(p_instance_id uuid,p_to text,p_reason text default null) returns void language plpgsql security definer set search_path=public as $$ declare i public.workflow_instances%rowtype; begin select * into i from public.workflow_instances where id=p_instance_id for update; if not found or not public.can_workflow('workflows.transition',i.tenant_id,i.organization_id,i.facility_id) or coalesce(trim(p_reason),'')='' then raise exception 'Workflow transition denied'; end if; update public.workflow_instances set state_key=p_to,revision=revision+1,updated_at=now(),updated_by=auth.uid() where id=i.id; perform public.record_trusted_workflow_event(i.id,'transition','instance.transition',jsonb_build_object('from',i.state_key,'to',p_to)); end $$;
create or replace function public.assign_workflow_instance(p_instance_id uuid,p_assignee_id uuid,p_reason text default null) returns void language plpgsql security definer set search_path=public as $$ declare i public.workflow_instances%rowtype; begin select * into i from public.workflow_instances where id=p_instance_id for update; if not found or not public.can_workflow(case when i.assignee_id is null then 'workflows.assign' else 'workflows.reassign' end,i.tenant_id,i.organization_id,i.facility_id) or (i.assignee_id is not null and coalesce(trim(p_reason),'')='') or not exists(select 1 from public.memberships m where m.user_id=p_assignee_id and m.active and m.tenant_id=i.tenant_id and (m.organization_id is null or m.organization_id=i.organization_id) and (m.facility_id is null or m.facility_id=i.facility_id)) then raise exception 'Workflow assignment denied'; end if; update public.workflow_instances set assignee_id=p_assignee_id,updated_at=now(),updated_by=auth.uid() where id=i.id; perform public.record_trusted_workflow_event(i.id,'assignment','instance.assigned',jsonb_build_object('reason',p_reason)); end $$;
revoke all on function public.enforce_workflow_scope() from public,anon,authenticated; revoke all on function public.validate_workflow_definition(jsonb) from public,anon; grant execute on function public.validate_workflow_definition(jsonb) to authenticated; revoke all on function public.publish_workflow_version(uuid,uuid),public.record_trusted_workflow_event(uuid,text,text,jsonb),public.start_workflow_instance(uuid,text,uuid,text),public.transition_workflow_instance(uuid,text,text),public.assign_workflow_instance(uuid,uuid,text) from public,anon; grant execute on function public.publish_workflow_version(uuid,uuid),public.record_trusted_workflow_event(uuid,text,text,jsonb),public.start_workflow_instance(uuid,text,uuid,text),public.transition_workflow_instance(uuid,text,text),public.assign_workflow_instance(uuid,uuid,text) to authenticated;
